mapper.select:
select hte.id as hte_id, hte.name, hte.dept_id, (SELECT COUNT(*) FROM hlvr_training_exam_detail hted WHERE hte.id = hted.ht_id AND hted.del_flag = 0) AS optCardNum, (SELECT COUNT(*) FROM hlvr_te_batch htb WHERE htb.hted_id in (select id from hlvr_training_exam_detail hted where ht_id = hte.id )) AS num, (select COUNT(DISTINCT create_by) from hlvr_te_batch where hted_id in (select id from hlvr_training_exam_detail hted where ht_id = hte.id )) AS people, (SELECT COUNT(*) FROM sys_user sd WHERE sd.dept_id = hte.dept_id AND sd.del_flag = 0) AS peopleAcc from hlvr_training_exam hte where hte.del_flag = 0
and dept_id = #{param.deptId}
and type = #{param.type}
and name like '%${param.name}%'
ORDER BY hte.update_time desc
